<?php
 namespace WPAICG\AutoGPT\Cron\Queuer\Helpers; if (!defined('ABSPATH')) { exit; } function update_task_flag_logic(\wpdb $wpdb, string $tasks_table_name, int $task_id, array $task_config): void { if (isset($task_config['index_existing_now_flag']) && $task_config['index_existing_now_flag'] === '1') { $task_config['index_existing_now_flag'] = '0'; $wpdb->update( $tasks_table_name, ['task_config' => wp_json_encode($task_config)], ['id' => $task_id] ); } } 